{
  "name": "Adega 3º Turno",
  "description": "A premium late-night beverage delivery experience featuring an AI-powered sommelier, curated combos, and lightning-fast service for the night owls.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Category = 'Cervejas' | 'Vinhos' | 'Destilados' | 'Combos' | 'Não Alcoólicos' | 'Petiscos';

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: Category;
  imageUrl: string;
  featured?: boolean;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface UserLocation {
  lat: number;
  lng: number;
  address?: string;
}

export interface AIResponse {
  message: string;
  recommendations?: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { PRODUCTS } from "../data";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAISuggestion = async (prompt: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: `Você é o "Sommelier do 3º Turno", um especialista em bebidas e entretenimento noturno para a Adega 3º Turno. 
        Sua missão é sugerir bebidas do nosso catálogo com base no humor, ocasião ou preferência do cliente.
        Seja descontraído, educado e rápido.
        Nosso catálogo inclui: ${PRODUCTS.map(p => `${p.name} (${p.category})`).join(', ')}.
        Sempre retorne sua resposta em formato JSON.`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            message: {
              type: Type.STRING,
              description: "A mensagem amigável de recomendação."
            },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Nomes exatos dos produtos recomendados."
            }
          },
          required: ["message", "recommendations"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Erro no Gemini:", error);
    return {
      message: "Tive um pequeno problema para pensar agora, mas recomendo dar uma olhada nos nossos Combos, são os favoritos da galera!",
      recommendations: ["Combo Absolut + Red Bull"]
    };
  }
};

import React from 'react';

interface NavbarProps {
  cartCount: number;
  onCartClick: () => void;
  onAISommelierClick: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ cartCount, onCartClick, onAISommelierClick }) => {
  return (
    <nav className="fixed top-0 left-0 right-0 z-50 bg-black/80 backdrop-blur-md border-b border-white/10">
      <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-purple-600 rounded-lg flex items-center justify-center font-bold text-xl neon-border">
            3T
          </div>
          <span className="font-serif text-2xl tracking-tighter hidden sm:block">Adega 3º Turno</span>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={onAISommelierClick}
            className="hidden md:flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-sm font-medium"
          >
            <span className="text-purple-400">✨</span> Sommelier AI
          </button>

          <button 
            onClick={onCartClick}
            className="relative p-2 text-white hover:text-purple-400 transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" />
            </svg>
            {cartCount > 0 && (
              <span className="absolute -top-1 -right-1 bg-purple-600 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full ring-2 ring-black">
                {cartCount}
              </span>
            )}
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState } from 'react';
import { getAISuggestion } from '../services/geminiService';

interface AISommelierProps {
  onClose: () => void;
  onAddToCart: (productName: string) => void;
}

const AISommelier: React.FC<AISommelierProps> = ({ onClose, onAddToCart }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState<{ message: string; recommendations: string[] } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    setLoading(true);
    const result = await getAISuggestion(input);
    setResponse(result);
    setLoading(false);
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-neutral-900 border border-white/10 w-full max-w-lg rounded-2xl shadow-2xl overflow-hidden">
        <div className="p-6 border-b border-white/5 flex justify-between items-center bg-gradient-to-r from-purple-900/20 to-transparent">
          <div>
            <h2 className="text-xl font-bold flex items-center gap-2">
              <span className="text-2xl">✨</span> Sommelier do 3º Turno
            </h2>
            <p className="text-xs text-neutral-400">Diga o que está sentindo e eu escolho seu drink.</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/5 rounded-full transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="p-6 h-[400px] flex flex-col gap-4 overflow-y-auto">
          {!response && !loading && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-4 opacity-50">
              <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center text-3xl">🤖</div>
              <p className="text-sm">"Estou com preguiça de escolher, o que você recomenda para uma noite fria?"</p>
            </div>
          )}

          {loading && (
            <div className="flex flex-col items-center justify-center h-full space-y-4">
              <div className="w-8 h-8 border-2 border-purple-500 border-t-transparent rounded-full animate-spin"></div>
              <p className="text-sm text-neutral-400">Consultando a adega...</p>
            </div>
          )}

          {response && (
            <div className="space-y-6">
              <div className="bg-white/5 p-4 rounded-xl border border-white/5">
                <p className="text-sm leading-relaxed">{response.message}</p>
              </div>
              <div className="grid grid-cols-1 gap-2">
                {response.recommendations.map((item, idx) => (
                  <button
                    key={idx}
                    onClick={() => onAddToCart(item)}
                    className="flex items-center justify-between p-3 rounded-lg bg-purple-600/10 border border-purple-500/30 hover:bg-purple-600/20 transition-all text-sm text-purple-200"
                  >
                    <span>{item}</span>
                    <span className="bg-purple-500 text-white px-2 py-0.5 rounded text-[10px] font-bold">ADICIONAR</span>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleSubmit} className="p-4 bg-black/40 border-t border-white/10">
          <div className="flex gap-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Digite sua dúvida ou humor..."
              className="flex-1 bg-white/5 border border-white/10 rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-purple-500 transition-all"
            />
            <button
              disabled={loading || !input.trim()}
              className="bg-purple-600 hover:bg-purple-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors rounded-full p-2"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AISommelier;

import React, { useState, useEffect, useMemo } from 'react';
import { Product, CartItem, Category } from './types';
import { PRODUCTS, CATEGORIES } from './data';
import Navbar from './components/Navbar';
import AISommelier from './components/AISommelier';

const App: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState<Category | 'Tudo'>('Tudo');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isSommelierOpen, setIsSommelierOpen] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(p => {
      const matchesCategory = selectedCategory === 'Tudo' || p.category === selectedCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const total = useMemo(() => cart.reduce((acc, item) => acc + item.price * item.quantity, 0), [cart]);

  const handleAIAddToCart = (name: string) => {
    const product = PRODUCTS.find(p => p.name.toLowerCase().includes(name.toLowerCase()));
    if (product) {
      addToCart(product);
      setIsSommelierOpen(false);
    }
  };

  return (
    <div className="min-h-screen pb-20">
      <Navbar 
        cartCount={cart.length} 
        onCartClick={() => setIsCartOpen(true)}
        onAISommelierClick={() => setIsSommelierOpen(true)}
      />

      {/* Hero Section */}
      <section className="relative h-[60vh] flex items-center justify-center overflow-hidden">
        <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1514362545857-3bc16c4c7d1b?auto=format&fit=crop&q=80&w=2000')] bg-cover bg-center opacity-30"></div>
        <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent"></div>
        <div className="relative z-10 text-center px-4 max-w-3xl">
          <h2 className="text-purple-500 font-bold tracking-[0.3em] text-sm mb-4 uppercase animate-pulse">Servindo agora</h2>
          <h1 className="text-5xl md:text-7xl font-serif mb-6 leading-tight">O Sabor Que A Noite Merece</h1>
          <p className="text-lg text-neutral-400 mb-8 max-w-xl mx-auto">
            Bebidas geladas, combos explosivos e entrega rápida. O 3º turno nunca foi tão bem servido.
          </p>
          <div className="flex flex-wrap justify-center gap-4">
            <button 
              onClick={() => setIsSommelierOpen(true)}
              className="px-8 py-3 bg-white text-black font-bold rounded-full hover:bg-purple-500 hover:text-white transition-all transform hover:scale-105"
            >
              Consultar AI Sommelier
            </button>
            <a 
              href="#catalogo"
              className="px-8 py-3 border border-white/20 backdrop-blur-md rounded-full hover:bg-white/10 transition-all"
            >
              Ver Cardápio
            </a>
          </div>
        </div>
      </section>

      {/* Main Content */}
      <main id="catalogo" className="max-w-7xl mx-auto px-4 py-12">
        {/* Search & Categories */}
        <div className="flex flex-col md:flex-row gap-6 mb-12 items-center justify-between">
          <div className="flex gap-3 overflow-x-auto pb-4 md:pb-0 w-full md:w-auto scrollbar-hide">
            <button 
              onClick={() => setSelectedCategory('Tudo')}
              className={`px-6 py-2 rounded-full whitespace-nowrap transition-all text-sm font-medium ${selectedCategory === 'Tudo' ? 'bg-purple-600 border-purple-500' : 'bg-white/5 border-white/10 hover:bg-white/10'} border`}
            >
              Tudo
            </button>
            {CATEGORIES.map(cat => (
              <button 
                key={cat.name}
                onClick={() => setSelectedCategory(cat.name as Category)}
                className={`px-6 py-2 rounded-full whitespace-nowrap transition-all text-sm font-medium flex items-center gap-2 ${selectedCategory === cat.name ? 'bg-purple-600 border-purple-500' : 'bg-white/5 border-white/10 hover:bg-white/10'} border`}
              >
                <span>{cat.icon}</span> {cat.name}
              </button>
            ))}
          </div>

          <div className="relative w-full md:w-64">
            <input 
              type="text" 
              placeholder="Buscar bebida..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-full px-10 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500/50"
            />
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-4 top-1/2 -translate-y-1/2 text-neutral-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
        </div>

        {/* Product Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
          {filteredProducts.map(product => (
            <div 
              key={product.id}
              className="group bg-neutral-900/50 border border-white/5 rounded-2xl overflow-hidden hover:border-purple-500/30 transition-all duration-300 flex flex-col"
            >
              <div className="aspect-[4/5] overflow-hidden relative">
                <img 
                  src={product.imageUrl} 
                  alt={product.name}
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                />
                {product.featured && (
                  <span className="absolute top-4 left-4 bg-purple-600 text-[10px] font-bold px-2 py-1 rounded tracking-widest uppercase shadow-lg">
                    Destaque
                  </span>
                )}
                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                  <button 
                    onClick={() => addToCart(product)}
                    className="bg-white text-black font-bold px-6 py-2 rounded-full transform translate-y-4 group-hover:translate-y-0 transition-all"
                  >
                    Adicionar
                  </button>
                </div>
              </div>
              <div className="p-5 flex-1 flex flex-col">
                <span className="text-xs text-purple-400 font-medium mb-1">{product.category}</span>
                <h3 className="font-bold text-lg mb-2 leading-tight">{product.name}</h3>
                <p className="text-neutral-500 text-xs mb-4 line-clamp-2">{product.description}</p>
                <div className="mt-auto flex items-center justify-between">
                  <span className="text-xl font-bold">R$ {product.price.toFixed(2)}</span>
                  <button 
                    onClick={() => addToCart(product)}
                    className="p-2 bg-white/5 border border-white/10 rounded-full hover:bg-purple-600 hover:text-white transition-all sm:hidden"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                    </svg>
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        {filteredProducts.length === 0 && (
          <div className="text-center py-20 space-y-4">
            <div className="text-6xl">🍹</div>
            <h3 className="text-xl font-medium">Nenhum resultado encontrado</h3>
            <p className="text-neutral-500">Tente buscar por outro termo ou mudar a categoria.</p>
            <button 
              onClick={() => {setSearchQuery(''); setSelectedCategory('Tudo');}}
              className="text-purple-400 hover:underline"
            >
              Limpar filtros
            </button>
          </div>
        )}
      </main>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-w-md bg-neutral-900 h-full flex flex-col shadow-2xl animate-slide-left">
            <div className="p-6 border-b border-white/5 flex items-center justify-between">
              <h2 className="text-xl font-bold">Seu Carrinho</h2>
              <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-white/5 rounded-full">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              {cart.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-center opacity-50 space-y-4">
                  <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center text-3xl">🛒</div>
                  <p>Sua adega está vazia.</p>
                  <button onClick={() => setIsCartOpen(false)} className="text-purple-400 font-medium">Voltar às compras</button>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="flex gap-4">
                    <img src={item.imageUrl} className="w-20 h-20 object-cover rounded-lg" alt="" />
                    <div className="flex-1">
                      <div className="flex justify-between mb-1">
                        <h4 className="font-bold text-sm">{item.name}</h4>
                        <button onClick={() => removeFromCart(item.id)} className="text-neutral-500 hover:text-red-500">
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                          </svg>
                        </button>
                      </div>
                      <p className="text-xs text-neutral-400 mb-3">R$ {item.price.toFixed(2)}</p>
                      <div className="flex items-center gap-3">
                        <div className="flex items-center border border-white/10 rounded-lg overflow-hidden">
                          <button onClick={() => updateQuantity(item.id, -1)} className="px-2 py-1 hover:bg-white/5 transition-colors">-</button>
                          <span className="px-3 text-xs font-bold">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)} className="px-2 py-1 hover:bg-white/5 transition-colors">+</button>
                        </div>
                        <span className="text-sm font-bold ml-auto">R$ {(item.price * item.quantity).toFixed(2)}</span>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>

            {cart.length > 0 && (
              <div className="p-6 border-t border-white/5 bg-black/40 space-y-4">
                <div className="flex justify-between items-center text-sm">
                  <span className="text-neutral-400">Subtotal</span>
                  <span className="font-bold">R$ {total.toFixed(2)}</span>
                </div>
                <div className="flex justify-between items-center text-sm">
                  <span className="text-neutral-400">Entrega</span>
                  <span className="text-green-500 font-bold uppercase text-[10px] tracking-widest">Grátis</span>
                </div>
                <div className="flex justify-between items-center text-lg font-bold border-t border-white/5 pt-4">
                  <span>Total</span>
                  <span className="text-purple-400">R$ {total.toFixed(2)}</span>
                </div>
                <button className="w-full bg-purple-600 hover:bg-purple-500 text-white font-bold py-4 rounded-xl transition-all shadow-lg neon-border">
                  Finalizar Pedido
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Sommelier Modal */}
      {isSommelierOpen && (
        <AISommelier 
          onClose={() => setIsSommelierOpen(false)} 
          onAddToCart={handleAIAddToCart}
        />
      )}

      {/* Floating Action Button for AI (Mobile Only) */}
      <button 
        onClick={() => setIsSommelierOpen(true)}
        className="fixed bottom-24 right-6 z-40 bg-purple-600 w-14 h-14 rounded-full flex items-center justify-center shadow-2xl md:hidden neon-border animate-bounce"
      >
        <span className="text-2xl">✨</span>
      </button>

      {/* Footer */}
      <footer className="border-t border-white/5 bg-neutral-900/50 py-12">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="w-12 h-12 bg-purple-600 rounded-lg flex items-center justify-center font-bold text-2xl mx-auto mb-6 neon-border">3T</div>
          <p className="text-sm text-neutral-500 mb-8 max-w-md mx-auto">
            Beba com moderação. Venda proibida para menores de 18 anos. 
            Entregas em toda a região metropolitana durante a madrugada.
          </p>
          <div className="flex justify-center gap-6 text-neutral-400 text-xs uppercase tracking-widest">
            <a href="#" className="hover:text-white transition-colors">Termos</a>
            <a href="#" className="hover:text-white transition-colors">Privacidade</a>
            <a href="#" className="hover:text-white transition-colors">Contato</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

export type Category = 'Cervejas' | 'Vinhos' | 'Destilados' | 'Combos' | 'Narguile' | 'Não Alcoólicos' | 'Petiscos';

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: Category;
  imageUrl: string;
  featured?: boolean;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface UserLocation {
  lat: number;
  lng: number;
  address?: string;
}

export interface AIResponse {
  message: string;
  recommendations?: string[];
}

import React from 'react';

interface NavbarProps {
  cartCount: number;
  onCartClick: () => void;
  onAISommelierClick: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ cartCount, onCartClick, onAISommelierClick }) => {
  return (
    <nav className="fixed top-0 left-0 right-0 z-50 bg-black/90 backdrop-blur-md border-b border-amber-500/20">
