import React, { useState } from 'react';
import { getAISuggestion } from '../services/geminiService';

interface AISommelierProps {
  onClose: () => void;
  onAddToCart: (productName: string) => void;
}

const AISommelier: React.FC<AISommelierProps> = ({ onClose, onAddToCart }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState<{ message: string; recommendations: string[] } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    setLoading(true);
    const result = await getAISuggestion(input);
    setResponse(result);
    setLoading(false);
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
      <div className="bg-neutral-900 border border-amber-500/30 w-full max-w-lg rounded-3xl shadow-[0_0_50px_rgba(251,191,36,0.15)] overflow-hidden">
        <div className="p-6 border-b border-white/5 flex justify-between items-center bg-gradient-to-r from-amber-500/10 to-transparent">
          <div>
            <h2 className="text-xl font-bold flex items-center gap-2">
              <span className="text-2xl">✨</span> Sommelier 3º Turno
            </h2>
            <p className="text-xs text-neutral-400">O Homer aprova, a gente entrega.</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/5 rounded-full transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="p-6 h-[350px] flex flex-col gap-4 overflow-y-auto">
          {!response && !loading && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-4 opacity-50">
              <div className="w-20 h-20 bg-amber-500/10 rounded-full flex items-center justify-center text-4xl">🍺</div>
              <p className="text-sm max-w-xs">"Manda uma recomendação aí! O que combina com um arguile hoje?"</p>
            </div>
          )}

          {loading && (
            <div className="flex flex-col items-center justify-center h-full space-y-4">
              <div className="w-10 h-10 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
              <p className="text-sm font-bold text-amber-500 tracking-widest uppercase">Consultando a adega...</p>
            </div>
          )}

          {response && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
              <div className="bg-white/5 p-5 rounded-2xl border border-white/5 relative">
                <div className="absolute -top-3 -left-2 bg-amber-500 text-black font-bold text-[10px] px-2 py-0.5 rounded">SUGESTÃO</div>
                <p className="text-sm leading-relaxed italic">"{response.message}"</p>
              </div>
              <div className="grid grid-cols-1 gap-2">
                {response.recommendations.map((item, idx) => (
                  <button
                    key={idx}
                    onClick={() => onAddToCart(item)}
                    className="flex items-center justify-between p-4 rounded-xl bg-amber-500/10 border border-amber-500/20 hover:border-amber-500 hover:bg-amber-500/20 transition-all text-sm group"
                  >
                    <span className="font-bold text-amber-100">{item}</span>
                    <span className="bg-amber-500 text-black px-3 py-1 rounded-lg text-[10px] font-black group-hover:scale-110 transition-transform">PEGAR AGORA</span>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleSubmit} className="p-5 bg-black/40 border-t border-white/10">
          <div className="flex gap-3">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ex: O que beber com menta?"
              className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-5 py-3 text-sm focus:outline-none focus:border-amber-500 transition-all"
            />
            <button
              disabled={loading || !input.trim()}
              className="bg-amber-500 hover:bg-amber-400 text-black disabled:opacity-50 disabled:cursor-not-allowed transition-all rounded-2xl px-4 font-bold shadow-lg"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
              </svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AISommelier;

import React, { useState, useEffect, useMemo } from 'react';
import { Product, CartItem, Category } from './types';
import { PRODUCTS, CATEGORIES } from './data';
import Navbar from './components/Navbar';
import AISommelier from './components/AISommelier';

const App: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState<Category | 'Tudo'>('Tudo');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isSommelierOpen, setIsSommelierOpen] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(p => {
      const matchesCategory = selectedCategory === 'Tudo' || p.category === selectedCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const total = useMemo(() => cart.reduce((acc, item) => acc + item.price * item.quantity, 0), [cart]);

  const handleAIAddToCart = (name: string) => {
    const product = PRODUCTS.find(p => p.name.toLowerCase().includes(name.toLowerCase()));
    if (product) {
      addToCart(product);
      setIsSommelierOpen(false);
    }
  };

  return (
