                e.currentTarget.src = "https://i.ibb.co/37zX2C8/homer-placeholder.png";
              }}
            />
          </div>

          <h2 className="text-amber-500 font-black tracking-[0.4em] text-xs mb-4 uppercase">Entrega em toda a região</h2>
          <h1 className="text-6xl md:text-8xl font-serif mb-6 leading-none italic tracking-tighter">
            3º <span className="text-amber-500 not-italic">Turno</span>
          </h1>
          <p className="text-lg md:text-xl text-neutral-400 mb-10 max-w-2xl font-medium leading-relaxed">
            A conveniência que a sua madrugada precisa. Cerveja trincando, arguile preparado e o melhor atendimento da cidade.
          </p>

          <div className="flex flex-wrap justify-center gap-5">
            <button 
