              className="px-10 py-4 bg-amber-500 text-black font-black rounded-2xl hover:bg-amber-400 transition-all transform hover:scale-105 shadow-[0_10px_30px_rgba(251,191,36,0.3)] uppercase tracking-widest text-sm"
