import React, { useState } from 'react';
import { getAISuggestion } from '../services/geminiService';

interface AISommelierProps {
  onClose: () => void;
  onAddToCart: (productName: string) => void;
}

const AISommelier: React.FC<AISommelierProps> = ({ onClose, onAddToCart }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState<{ message: string; recommendations: string[] } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    setLoading(true);
    const result = await getAISuggestion(input);
    setResponse(result);
    setLoading(false);
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/90 backdrop-blur-sm">
      <div className="bg-neutral-950 border border-[#FFD90F]/30 w-full max-w-lg rounded-[2.5rem] shadow-[0_0_60px_rgba(255,217,15,0.1)] overflow-hidden">
        <div className="p-8 border-b border-white/5 flex justify-between items-center bg-gradient-to-br from-[#FFD90F]/10 via-transparent to-transparent">
          <div>
            <h2 className="text-xl font-black uppercase tracking-widest flex items-center gap-3">
              <img src="logo.png" className="w-8 h-8 object-contain" alt="" />
              Sommelier
            </h2>
            <p className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest mt-1">O Homer ajuda você a escolher</p>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-white/5 rounded-2xl transition-all">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="p-8 h-[380px] flex flex-col gap-4 overflow-y-auto custom-scrollbar">
          {!response && !loading && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-6 opacity-40">
              <img src="logo.png" className="w-24 h-24 object-contain grayscale" alt="" />
              <p className="text-sm font-medium italic max-w-xs">"Diz aí, o que você quer beber ou fumar hoje? Estou pronto para sugerir o melhor!"</p>
            </div>
          )}

          {loading && (
            <div className="flex flex-col items-center justify-center h-full space-y-6">
              <div className="w-12 h-12 border-4 border-[#FFD90F] border-t-transparent rounded-full animate-spin"></div>
              <p className="text-[10px] font-black text-[#FFD90F] tracking-[0.3em] uppercase">Vasculhando o 3º Turno...</p>
            </div>
          )}

          {response && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-6 duration-500">
              <div className="bg-white/5 p-6 rounded-3xl border border-white/5 relative">
                <div className="absolute -top-3 left-6 bg-[#FFD90F] text-black font-black text-[9px] px-3 py-1 rounded-full uppercase tracking-widest shadow-xl">Recomendação</div>
                <p className="text-sm leading-relaxed text-neutral-200">"{response.message}"</p>
              </div>
              <div className="grid grid-cols-1 gap-3">
                {response.recommendations.map((item, idx) => (
                  <button
                    key={idx}
                    onClick={() => onAddToCart(item)}
                    className="flex items-center justify-between p-5 rounded-2xl bg-[#FFD90F]/5 border border-[#FFD90F]/10 hover:border-[#FFD90F] hover:bg-[#FFD90F]/10 transition-all text-sm group"
                  >
                    <span className="font-bold text-[#FFD90F]">{item}</span>
                    <span className="bg-[#FFD90F] text-black px-4 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-tighter group-hover:scale-110 transition-transform shadow-lg">Adicionar</span>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleSubmit} className="p-6 bg-black border-t border-white/5">
          <div className="flex gap-3">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ex: O que combina com um arguile?"
              className="flex-1 bg-neutral-900 border border-white/10 rounded-2xl px-6 py-4 text-sm focus:outline-none focus:border-[#FFD90F] transition-all placeholder:text-neutral-600"
            />
            <button
              disabled={loading || !input.trim()}
              className="bg-[#FFD90F] hover:bg-[#ffe65c] text-black disabled:opacity-50 disabled:cursor-not-allowed transition-all rounded-2xl px-6 shadow-xl"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M14 5l7 7m0 0l-7 7m7-7H3" />
              </svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

